CREATE TRIGGER [dbo].[BillOfMaterialPart_History]ON [dbo].[BillOfMaterialPart]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfMaterialPartId IS NOT NULL AND d.BillOfMaterialPartId IS NULL THEN 'I' 		WHEN i.BillOfMaterialPartId IS NOT NULL AND d.BillOfMaterialPartId IS NOT NULL THEN 'U' 		WHEN i.BillOfMaterialPartId IS NULL AND d.BillOfMaterialPartId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfMaterialPartId = d.BillOfMaterialPartId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfMaterialPart([BillOfMaterialPartId], [BillOfMaterialId], [PartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfMaterialPartId], [BillOfMaterialId], [PartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfMaterialPart([BillOfMaterialPartId], [BillOfMaterialId], [PartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfMaterialPartId], [BillOfMaterialId], [PartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND